@@ -7031,6 +7032,32 @@ Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
                             ConstantInt::get(Op1->getType(), ~(*C)));
     }

+    // Transform icmp pred xor(~X, Y), ~X  -->  icmp swapped_pred (X ^ Y), X
+    // Transform icmp pred ~X, xor(~X, Y)  -->  icmp pred (X ^ Y), X
+    {
+      Value *X, *Y;
+      // Pattern: icmp pred, xor(~X, Y), ~X  or  icmp pred, xor(Y, ~X), ~X
+      if (match(Op1, m_Not(m_Value(X)))) {
+        // Check if Op0 is xor(~X, Y) or xor(Y, ~X)
+        if (match(Op0, m_Xor(m_Specific(Op1), m_Value(Y))) ||
+            match(Op0, m_Xor(m_Value(Y), m_Specific(Op1)))) {
+          Value *XorXY = Builder.CreateXor(X, Y);
+          // xor(~X, Y) pred ~X  -->  (X ^ Y) swapped_pred X
+          return new ICmpInst(I.getSwappedPredicate(), XorXY, X);
+        }
+      }
+      // Pattern: icmp pred, ~X, xor(~X, Y)  or  icmp pred, ~X, xor(Y, ~X)
+      if (match(Op0, m_Not(m_Value(X)))) {
+        // Check if Op1 is xor(~X, Y) or xor(Y, ~X)
+        if (match(Op1, m_Xor(m_Specific(Op0), m_Value(Y))) ||
+            match(Op1, m_Xor(m_Value(Y), m_Specific(Op0)))) {
+          Value *XorXY = Builder.CreateXor(X, Y);
+          // ~X pred xor(~X, Y)  -->  (X ^ Y) pred X
+          return new ICmpInst(I.getPredicate(), XorXY, X);
+        }
+      }
+    }
+
     Instruction *AddI = nullptr;
     if (match(&I, m_UAddWithOverflow(m_Value(X), m_Value(Y),
